import React, { useState } from 'react';

const COLUMNS = [
  { key: 'todo', title: 'To Do' },
  { key: 'doing', title: 'In Progress' },
  { key: 'done', title: 'Done' },
];

const INITIAL = [
  { id: 'c1', text: 'Set up project', col: 'done' },
  { id: 'c2', text: 'Build the board', col: 'doing' },
  { id: 'c3', text: 'Wire drag & drop', col: 'doing' },
  { id: 'c4', text: 'Write tests', col: 'todo' },
  { id: 'c5', text: 'Ship it', col: 'todo' },
];

export default function Kanban() {
  const [cards, setCards] = useState(INITIAL);
  const [over, setOver] = useState(null);

  const onDrop = (e, col) => {
    e.preventDefault();
    const id = e.dataTransfer.getData('text/plain');
    setCards((cs) => cs.map((c) => (c.id === id ? { ...c, col } : c)));
    setOver(null);
  };

  return (
    <div style={{ display: 'flex', gap: 12 }}>
      {COLUMNS.map((col) => (
        <div
          key={col.key}
          onDragOver={(e) => { e.preventDefault(); setOver(col.key); }}
          onDragLeave={() => setOver((o) => (o === col.key ? null : o))}
          onDrop={(e) => onDrop(e, col.key)}
          style={{ flex: 1, minHeight: 220, background: over === col.key ? '#dbeafe' : '#f1f5f9', borderRadius: 10, padding: 10 }}
        >
          <h3 style={{ margin: '4px 0 10px', fontSize: 14, color: '#475569' }}>
            {col.title} ({cards.filter((c) => c.col === col.key).length})
          </h3>
          {cards.filter((c) => c.col === col.key).map((card) => (
            <div
              key={card.id}
              draggable
              onDragStart={(e) => e.dataTransfer.setData('text/plain', card.id)}
              style={{ background: '#fff', borderRadius: 8, padding: '10px 12px', marginBottom: 8, boxShadow: '0 1px 3px rgba(0,0,0,0.12)', cursor: 'grab' }}
            >
              {card.text}
            </div>
          ))}
        </div>
      ))}
    </div>
  );
}

